def minPath(grid, k):
    N = len(grid)
    directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]

    def is_valid(x, y):
        return 0 <= x < N and 0 <= y < N

    def dfs(x, y, path):
        if len(path) == k:
            return path

        min_path = None
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if is_valid(nx, ny):
                new_path = dfs(nx, ny, path + [grid[nx][ny]])
                if min_path is None or new_path < min_path:
                    min_path = new_path
        return min_path

    min_path = None
    for i in range(N):
        for j in range(N):
            path = dfs(i, j, [grid[i][j]])
            if min_path is None or path < min_path:
                min_path = path

    return min_path

# Example usage:
